import React, { useState, useEffect } from 'react';
import { YMaps, Map, Placemark } from '@pbe/react-yandex-maps';

import constFlaskURL from '../consts/constFlaskURL'

function TestHome() {
  const [center, setCenter] = useState([55.751574, 37.573856]);
  const [markers, setMarkers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedMarker, setSelectedMarker] = useState(null);

  // Загрузка маркеров из БД
  useEffect(() => {
    fetchMarkersFromDatabase();
  }, []);

  const fetchMarkersFromDatabase = async () => {
    try {
      setLoading(true);

      // В реальном приложении здесь будет запрос к вашему API
      const response = await constFlaskURL.get('/localities/crossroads');

      const loadData = {
        items: [
            {
            crossroads: {
                latitude: response.data.items[0].crossroads.latitude,
                longitude: response.data.items[0].crossroads.longitude,
                roads_sings: {
                    name_road: response.data.items[0].crossroads.roads_sings.name_road,
                    number_road: response.data.items[0].crossroads.roads_sings.number_road,
                    sings: {
                        image: "images.jpg",
                        latitude: response.data.items[0].crossroads.roads_sings.sings.latitude,
                        longitude: response.data.items[0].crossroads.roads_sings.sings.longitude,
                        name_sing: response.data.items[0].crossroads.roads_sings.sings.name_sing,
                        sing_id: response.data.items[0].crossroads.roads_sings.sings.sing_id
                    }
                },
                type_crossroad: response.data.items[0].crossroads.type_crossroad
            },
            id: response.data.items[0].id,
            latitude: response.data.items[0].latitude,
            longitude: response.data.items[0].longitude,
            name_locality: response.data.items[0].name_locality
            }
        ]
      }
    setMarkers(loadData.items);

    if (loadData.items.length > 0) {
      setCenter([loadData.items[0].crossroads.roads_sings.sings.latitude, loadData.items[0].crossroads.roads_sings.sings.longitude]);
    }

  } catch (error) {
    console.error('Ошибка загрузки маркеров:', error);
  } finally {
    setLoading(false);
  }
  };

  // Функция для генерации HTML балуна с изображением
  const generateBalloonContent = (marker) => {
    return `
      <div style="
        max-width: 400px; 
        font-family: Arial, sans-serif;
        background: white;
        border-radius: 12px;
        overflow: hidden;
        box-shadow: 0 5px 20px rgba(0,0,0,0.15);
      ">
        <!-- Изображение -->
        <div style="position: relative; height: 200px; overflow: hidden;">
          <img 
            src="${marker.crossroads.roads_sings.sings.image}" 
            style="
              width: 100%;
              height: 100%;
              object-fit: cover;
              transition: transform 0.3s;
            "
            onmouseover="this.style.transform='scale(1.05)'"
            onmouseout="this.style.transform='scale(1)'"
          />
        </div>

        <!-- Информация -->
        <div style="padding: 20px;">
          <h3 style="
            margin: 0 0 10px 0;
            color: #333;
            font-size: 20px;
            font-weight: 600;
          ">
            ${marker.crossroads.roads_sings.sings.name_sing}
          </h3>

          <!-- Координаты и адрес -->
          <div style="
            background: #f8f9fa;
            padding: 15px;
            border-radius: 8px;
            margin-bottom: 15px;
          ">
            <div style="
              display: grid;
              grid-template-columns: 1fr 1fr;
              gap: 10px;
              margin-bottom: 10px;
            ">
              <div>
                <div style="
                  font-size: 11px;
                  color: #888;
                  margin-bottom: 4px;
                ">
                  Широта
                </div>
                <div style="
                  font-family: 'Courier New', monospace;
                  font-size: 13px;
                  color: #333;
                  font-weight: bold;
                ">
                  ${marker.crossroads.roads_sings.sings.latitude.toFixed(6)}
                </div>
              </div>
              <div>
                <div style="
                  font-size: 11px;
                  color: #888;
                  margin-bottom: 4px;
                ">
                  Долгота
                </div>
                <div style="
                  font-family: 'Courier New', monospace;
                  font-size: 13px;
                  color: #333;
                  font-weight: bold;
                ">
                  ${marker.crossroads.roads_sings.sings.longitude.toFixed(6)}
                </div>
              </div>
            </div>

            <div>
              <div style="
                font-size: 11px;
                color: #888;
                margin-bottom: 4px;
              ">
                Адрес
              </div>
              <div style="
                font-size: 13px;
                color: #333;
              ">
                ${marker.name_locality}
              </div>
            </div>
          </div>
        </div>
      </div>
    `;
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '600px',
        flexDirection: 'column',
        gap: '20px'
      }}>
        <div style={{
          width: '50px',
          height: '50px',
          border: '5px solid #f3f3f3',
          borderTop: '5px solid #3498db',
          borderRadius: '50%',
          animation: 'spin 1s linear infinite'
        }}></div>
        <style>{`
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
        `}</style>
        <div>Загрузка карты и маркеров...</div>
      </div>
    );
  }

  return (
    <div style={{ 
      width: '100%', 
      maxWidth: '1200px', 
      margin: '0 auto',
      padding: '20px'
    }}>
      <h1 style={{ marginBottom: '20px', color: '#333' }}>
        Карта достопримечательностей
        <span style={{
          fontSize: '14px',
          color: '#666',
          marginLeft: '10px',
          backgroundColor: '#f0f0f0',
          padding: '4px 10px',
          borderRadius: '20px'
        }}>
          {markers.length} мест
        </span>
      </h1>

      <div style={{ 
        width: '100%', 
        height: '600px',
        borderRadius: '12px',
        overflow: 'hidden',
        boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
        marginBottom: '20px'
      }}>
        <YMaps>
          <Map 
            state={{ center, zoom: 10 }} 
            width="100%" 
            height="100%"
            modules={['geoObject.addon.balloon', 'geoObject.addon.hint']}
          >
            {markers.map((marker) => (
              <Placemark
                key={marker.id}
                geometry={[marker.crossroads.roads_sings.sings.latitude, marker.crossroads.roads_sings.sings.longitude]}
                options={{
                  iconLayout: 'default#image',
                  iconImageSize: [48, 48],
                  iconImageOffset: [-24, -48],
                  hideIconOnBalloonOpen: false,
                  openBalloonOnClick: true,
                }}
                properties={{
                  hintContent: `<div style="padding: 5px 10px; font-weight: bold;">${marker.crossroads.roads_sings.sings.name_sing}</div>`,
                  balloonContent: generateBalloonContent(marker),
                  balloonContentHeader: `<div style="padding: 10px; background: ${marker.color}; color: white; font-weight: bold; border-radius: 8px 8px 0 0;">${marker.name_locality}</div>`,
                }}
                modules={['geoObject.addon.balloon']}
                onClick={() => {
                  setSelectedMarker(marker);
                  console.log('Выбран маркер:', marker.name_locality);
                }}
              />
            ))}
          </Map>
        </YMaps>
      </div>
    </div>
  );
}

export default TestHome;
